/*Table structure for table `torneos` */

DROP TABLE IF EXISTS `torneos`;

CREATE TABLE `torneos` (
  `id` int NOT NULL AUTO_INCREMENT,
  `codigo_torneo` varchar(50) NOT NULL,
  `nombre` varchar(255) NOT NULL,
  `fecha_inicio` date DEFAULT NULL,
  `fecha_fin` date DEFAULT NULL,
  `activo_inscripcion` tinyint(1) DEFAULT '1',
  PRIMARY KEY (`id`),
  UNIQUE KEY `codigo_torneo` (`codigo_torneo`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb3;

/*Data for the table `torneos` */

insert  into `torneos`(`id`,`codigo_torneo`,`nombre`,`fecha_inicio`,`fecha_fin`,`activo_inscripcion`) values (1,'torneomixto-aeroclub','Torneo Abierto de Tenis Mixto \"Copa Aero Club\"','2026-03-09','2026-03-15',0),(2,'torneomal','torneomal','2025-01-01','2025-02-02',0),(3,'Torneo Dobles-aeroclub','Torneo Abierto Dobles Masc-Fem \"Copa Aero Club\"','2026-04-13','2026-04-19',1);

/*Table structure for table `usuario` */

DROP TABLE IF EXISTS `usuario`;

CREATE TABLE `usuario` (
  `id` int NOT NULL AUTO_INCREMENT,
  `nombre` varchar(100) NOT NULL,
  `pass` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `tipousuario` int DEFAULT NULL,
  `activo` tinyint(1) DEFAULT '1',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

